import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { CancelGatherParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/CancelGatherParser';

export class CancelGatherEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, CancelGatherParser);
    }

    public getParser(): CancelGatherParser {
        return this.parser as CancelGatherParser;
    }
}
